import { useState } from "react";
import "./PatientVisit.css";

export default function PatientVisit() {
  const [photo, setPhoto] = useState(null);

  return (
    <div className="visit-page">

      {/* ================= HEADER ================= */}
      <div className="visit-header">

        <div className="patient-box">
          <div className="avatar">
            {photo ? (
              <img src={photo} alt="" />
            ) : (
              "Upload"
            )}
            <input
              type="file"
              accept="image/*"
              onChange={(e) =>
                setPhoto(URL.createObjectURL(e.target.files[0]))
              }
            />
          </div>

          <div className="patient-info">
            <input defaultValue="Patient Name" />
            <div className="meta">Age | Blood Group | Gender</div>
          </div>
        </div>

        <div className="pt-id">PT123456</div>
      </div>

      {/* ================= VISIT DETAILS ================= */}
      <div className="card">
        <h3>Visit Details</h3>

        <div className="grid-4">
          <div>
            <label>Visit ID</label>
            <select>
              <option>V12345</option>
            </select>
          </div>

          <div>
            <label>Visit Type</label>
            <select>
              <option>OPD</option>
              <option>IPD</option>
            </select>
          </div>

          <div>
            <label>Visit Date & Time</label>
            <input type="datetime-local" />
          </div>

          <div>
            <label>Department</label>
            <select>
              <option>General Medicine</option>
            </select>
          </div>

          <div>
            <label>Clinic / Location</label>
            <select>
              <option>OPD – Room 101</option>
            </select>
          </div>

          <div className="doctor-row">
            <div style={{ flex: 1 }}>
              <label>Attending Doctor</label>
              <input placeholder="Doctor Name" />
            </div>
            <button className="attach">Attach Card</button>
          </div>
        </div>
      </div>

      {/* ================= BILLING ================= */}
      <div className="card two-col">

        <div>
          <h3>Billing & Administrative</h3>

          <div className="grid-2">
            <div>
              <label>Patient Type</label>
              <select>
                <option>Insurance</option>
                <option>Cash</option>
              </select>
            </div>

            <div>
              <label>Insurance Expiry</label>
              <input type="date" />
            </div>

            <div>
              <label>Insurance Provider</label>
              <select>
                <option>ABC Health Insurance</option>
              </select>
            </div>

            <div>
              <label>Network</label>
              <select>
                <option>Network A</option>
              </select>
            </div>

            <div>
              <label>Member ID</label>
              <input />
            </div>

            <div>
              <label>Card Number</label>
              <input />
            </div>

            <div>
              <label>Referral Source</label>
              <input />
            </div>

            <div style={{ gridColumn: "span 2" }}>
              <label>Chief Complaint / Visit Reason</label>
              <textarea />
            </div>
          </div>
        </div>

        {/* ================= BENEFITS ================= */}
        <div>
          <h3>Schedule of Benefits</h3>

          {[
            "Consultation",
            "Diagnostic",
            "Lab Copay",
            "Radiology",
            "Pharmacy",
            "Dental",
            "Maternity",
            "Optical",
          ].map((item) => (
            <div key={item} className="benefits-row">
              <span>{item}</span>
              <input placeholder="Amount" />
            </div>
          ))}
        </div>
      </div>

      {/* ================= ACTIONS ================= */}
      <div className="actions">
        <button className="save">Save Visit</button>
        <button className="emr">Save & Go to EMR</button>
      </div>

    </div>
  );
}
